// ── Decompression ──
let _bloomBytes: Uint8Array | null = null;

async function getBloomBytes(): Promise<Uint8Array> {
  if (_bloomBytes) return _bloomBytes;

  // Decode base64
  const binaryString = atob(BLOOM_DATA_B64);
  const compressed = new Uint8Array(binaryString.length);
  for (let i = 0; i < binaryString.length; i++) {
    compressed[i] = binaryString.charCodeAt(i);
  }

  // Decompress using DecompressionStream (Web Streams API)
  if (typeof DecompressionStream !== 'undefined') {
    const ds = new DecompressionStream('deflate');
    const writer = ds.writable.getWriter();
    const reader = ds.readable.getReader();

    // Strip zlib header (2 bytes) and checksum (4 bytes) for raw deflate
    const rawDeflate = compressed.slice(2, compressed.length - 4);
    writer.write(rawDeflate);
    writer.close();

    const chunks: Uint8Array[] = [];
    let totalLen = 0;
    while (true) {
      const { done, value } = await reader.read();
      if (done) break;
      chunks.push(value);
      totalLen += value.length;
    }

    _bloomBytes = new Uint8Array(totalLen);
    let offset = 0;
    for (const chunk of chunks) {
      _bloomBytes.set(chunk, offset);
      offset += chunk.length;
    }
  } else {
    // Fallback: use pako-lite inline inflate
    // For environments without DecompressionStream (older browsers)
    throw new Error('DecompressionStream not available — bloom filter requires a modern browser');
  }

  return _bloomBytes;
}

// ── SHA-256 Hashing ──
async function sha256(data: Uint8Array): Promise<Uint8Array> {
  const hash = await crypto.subtle.digest('SHA-256', data.buffer as ArrayBuffer);
  return new Uint8Array(hash);
}

// ── Bloom Filter Query ──

/**
 * Check if a password is in the weak password bloom filter.
 * Uses SHA-256 double-hashing (Kirschner-Mitzenmacher).
 *
 * Normalization: NFKC + lowercase (matching Python implementation).
 *
 * @param password - The password to check
 * @returns true if password is LIKELY weak (FPR ~0.1%), false if definitely not in set
 */
export async function isWeakPassword(password: string): Promise<boolean> {
  try {
    const bloom = await getBloomBytes();

    // Normalize: NFKC + lowercase (matching Python's unicodedata.normalize('NFKC', pw).lower())
    const normalized = password.normalize('NFKC').toLowerCase();
    const encoded = new TextEncoder().encode(normalized);

    // SHA-256 double-hashing: h(i) = (h1 + i*h2) mod m
    const hash = await sha256(encoded);

    // h1 = first 8 bytes as uint64 (we use first 4 as uint32 for JS safety)
    const h1 = (hash[0] | (hash[1] << 8) | (hash[2] << 16) | ((hash[3] & 0x7f) << 24)) >>> 0;
    // h2 = next 8 bytes as uint64 (use bytes 4-7 as uint32)
    const h2 = (hash[4] | (hash[5] << 8) | (hash[6] << 16) | ((hash[7] & 0x7f) << 24)) >>> 0;

    for (let i = 0; i < BLOOM_K; i++) {
      const bit = ((h1 + i * h2) >>> 0) % BLOOM_M_BITS;
      const byteIdx = bit >>> 3;
      const bitMask = 1 << (bit & 7);
      if ((bloom[byteIdx] & bitMask) === 0) {
        return false; // Definitely not in set
      }
    }

    return true; // Probably in set (FPR ~0.1%)
  } catch {
    // If bloom filter fails to load, return false (don't block password entry)
    return false;
  }
}
